export class Processor extends Callable {
    static classes = [
        'image_processor_class',
        'tokenizer_class',
        'feature_extractor_class',
    ]

    constructor(config, components, chat_template) {
        super();
        this.config = config;
        this.components = components;
        this.chat_template = chat_template;
    }

    get image_processor() { return this.components.image_processor; }
    get tokenizer() { return this.components.tokenizer; }
    get feature_extractor() { return this.components.feature_extractor; }

    async _call(input, ...args) {
        // Default: try image_processor, then feature_extractor, then tokenizer
        for (const item of [this.image_processor, this.feature_extractor, this.tokenizer]) {
            if (item) return item(input, ...args);
        }
    }
}
```

