 * **Example:** Answer a question about an image w/ `onnx-community/SmolVLM-256M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'onnx-community/SmolVLM-256M-Instruct');
 * const image = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const prompt = 'USER: <image>\nDescribe this image in one sentence.\nASSISTANT:';
 * const output = await pipe(image, prompt, { max_new_tokens: 50 });
 * // [{ generated_text: 'Two cats are resting together on a couch.' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, text, generate_kwargs = {}) {
        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        const texts = Array.isArray(text) ? text : [text];

        // Modern VLM processors accept (images, text) together and return
        // {input_ids, attention_mask, pixel_values, ...} ready for generate().
        const inputs = await this.processor(preparedImages, texts, { padding: true });

        const outputTokenIds = /** @type {Tensor} */(await this.model.generate({
            ...inputs,
            ...generate_kwargs,
        }));

        // Decode full output (includes the prompt tokens for decoder-only VLMs).
        const decoded = this.tokenizer.batch_decode(outputTokenIds, {
            skip_special_tokens: true,
        });

        // Strip the prompt from each decoded string using the TextGenerationPipeline
        // pattern: decode the input_ids (skip special tokens) to measure prompt length,
        // then slice it off. Image placeholder tokens are special tokens and are skipped
        // by both decode calls, so lengths align correctly.
        const promptLengths = this.tokenizer.batch_decode(inputs.input_ids, {
            skip_special_tokens: true,
        }).map(x => x.length);

        const result = decoded.map((text, i) => ({
            generated_text: text.slice(promptLengths[i]).trim(),
        }));

        return isBatched ? result.map(x => [x]) : [result[0]];
    }
}
```

**Key design decisions:**

| Decision | Rationale |
|---|---|
| `_call(images, text, generate_kwargs)` | Modern VLMs require a prompt; making it a required param makes the API explicit |
| `prepareImages(images)` | Existing helper (line 91) normalises all image input types (URL, Blob, RawImage, etc.) |
| `processor(preparedImages, texts, {padding:true})` | Standard pattern for all VLM processors (LlavaProcessor, PaliGemmaProcessor, Qwen2VLProcessor, etc.) — one call returns merged image+text tensor dict |
| `model.generate({...inputs})` | Spreads processor output directly; `imageTextToTextForward` in models.js reads `pixel_values` + `input_ids` from the spread |
| Prompt-stripping via string length | Follows `TextGenerationPipeline` (lines 1053–1068) exactly; works at string level, not tensor level, avoiding Tensor.slice API ambiguity |
| Return shape for batched | `result.map(x => [x])` → `[[{generated_text}], [{generated_text}], ...]` matches `ImageToTextPipeline` convention |

---

### Change 3 — Register in `SUPPORTED_TASKS`

**Location:** `src/pipelines.js` after the `"image-to-text"` entry (line 3255), before `"image-classification"` (line 3257).

Insert:
```js
